const { ethers } = require('ethers');

async function swapTokens(provider, privateKey, fromTokenAddress, toTokenAddress, dexContractAddress, amount) {
  const signer = new ethers.Wallet(privateKey, provider);

  // Get the ERC20 token contract instances
  const fromTokenContract = new ethers.Contract(fromTokenAddress, ['function approve(address spender, uint256 amount) public'], signer);
  const toTokenContract = new ethers.Contract(toTokenAddress, ['function balanceOf(address account) public view returns (uint256)'], signer);

  // Get the DEX contract instance
  const dexContract = new ethers.Contract(dexContractAddress, ['function swap(uint256 amountIn, address[] memory path) public'], signer);

  // Approve the DEX to spend the tokens
  const approveTx = await fromTokenContract.approve(dexContractAddress, ethers.constants.MaxUint256);
  await approveTx.wait();

  // Get the current balance of the output token before swap
  const beforeBalance = await toTokenContract.balanceOf(signer.address);

  // Perform the swap
  const swapTx = await dexContract.swap(amount, [fromTokenAddress, toTokenAddress]);
  await swapTx.wait();

  // Get the current balance of the output token after swap
  const afterBalance = await toTokenContract.balanceOf(signer.address);

  console.log(`Swapped ${amount} tokens. Before: ${beforeBalance.toString()}, After: ${afterBalance.toString()}`);
}

